   175→/**
   176→ * Autoloader for AgentPress classes.
   177→ *
   178→ * @param string $class Class name to load.
   179→ */
   180→function agentpress_autoloader($class) {
   181→    // Only handle AgentPress namespace
   182→    if (strpos($class, 'AgentPress\\') !== 0) {
   183→        return;
   184→    }
   185→
   186→    // Remove namespace prefix
   187→    $class_name = str_replace('AgentPress\\', '', $class);
   188→
   189→    // Define class file mappings
   190→    $class_map = array(
   191→        'Parser' => 'includes/class-parser.php',
   192→        'Agents' => 'includes/class-agents.php',
   193→        'Logger' => 'includes/class-logger.php',
   194→        'Router' => 'includes/class-router.php',
   195→        'REST_API' => 'includes/class-rest-api.php',
   196→        'Admin' => 'admin/class-admin.php',
   197→        'Content_Writer' => 'includes/agents/class-content-writer.php',
   198→        'Image_Generator' => 'includes/agents/class-image-generator.php',
   199→    );
   200→
   201→    // Handle sub-namespaces like AgentPress\Agents\Content_Writer
   202→    if (strpos($class_name, '\\') !== false) {
   203→        $parts = explode('\\', $class_name);
   204→        $sub_namespace = strtolower($parts[0]);
   205→        $class_name = $parts[1];
   206→
   207→        $file = AGENTPRESS_PLUGIN_DIR . 'includes/' . $sub_namespace . '/class-' . strtolower(str_replace('_', '-', $class_name)) . '.php';
   208→    } else {
   209→        $file = AGENTPRESS_PLUGIN_DIR . (isset($class_map[$class_name]) ? $class_map[$class_name] : '');
   210→    }
   211→
   212→    if (file_exists($file)) {
   213→        require_once $file;
   214→    }
   215→}
   216→spl_autoload_register('agentpress_autoloader');
